var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"……대충 말뜻은 이해했다. 야크샤 부전대장.","JPN":"……だいたい理解した。ヤクシャー副戦隊長。","ENG":"...I see what you're getting at, Yaksha Deputy Commander.","TWN":"……我大概懂你的意思了。夜叉副戰隊長。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"요컨대 이번 작전에 그 신참 녀석을 참관시켜 달라는 뜻이로군.","JPN":"つまり、今回の作戦にその新入りを立ち会わせて欲しいということだな。","ENG":"You want us to bring the rookie along for the next operation to watch.","TWN":"總之，你是想讓新人觀摩這次作戰吧。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그렇습니다. 펜릴 전대장님.","JPN":"その通りです、フェンリル戦隊長。","ENG":"Yes, Fenrir Commander.","TWN":"是的，芬里爾戰隊長。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"마침, 펜릴 전대가 작전 수행을 위해 이 기지에서 물자를 보급받을 거라고 들었거든요.","JPN":"ちょうどフェンリル戦隊が作戦遂行のために、この基地で物資を補給する予定だと聞きましたので。","ENG":"I heard that the Fenrir Division was coming here for resupplies before the operation.","TWN":"我聽說芬里爾戰隊正好要在這個基地停留，進行物資補給。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"아직 외부에 노출되지 않은 작전으로 알고 있는데.","JPN":"まだその作戦については公表されてないはずだが。","ENG":"I was under the impression that this operation was not announced yet.","TWN":"我記得這個作戰並未向外部透露。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"여전히 관리국 소식에는 귀가 밝군.","JPN":"相変わらず管理局の情報に明るいな。","ENG":"I see you're still quick with news around the Administration.","TWN":"你在管理局的消息還是這麼靈通。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"하하, 작은 전대 나름의 생존전략이라고 해야할까요?","JPN":"あはは、小規模戦隊なりの生存戦略といったところでしょうか。","ENG":"Haha, let's say it's a survival tactic for small divisions like us.","TWN":"呵呵，這算是小戰隊自己的生存策略吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"펜릴 전대의 전대장이라고?","JPN":"フェンリル戦隊の戦隊長か？","ENG":"Is she the Commander of the Fenir Division?","TWN":"她是芬里爾戰隊的戰隊長？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"전대장이라는 게 이런 꼬맹이도…… ","JPN":"戦隊長って、こんなガキにも…… ","ENG":"So even a little kid like her can be a command–","TWN":"這種小鬼也能當戰隊長……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"커헉!?","JPN":"カハッ！？","ENG":"Kuh?!","TWN":"咳？！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"자자, 앨리스? 인사부터 해야지~?","JPN":"ささ、アリス？　挨拶がまだでしょ～?","ENG":"Now, now, Alice. Let's introduce you first.","TWN":"好了，艾莉絲？先打個招呼吧～？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"펜릴 전대장님, 이쪽이 야크샤의 견습 대원 앨리스 브레이드우드라고 합니다.","JPN":"フェンリル戦隊長、こちらがヤクシャーの見習い隊員、アリス・ブレイドウッドです。","ENG":"Fenrir Commander, this is Alice Braidwood, Yaksha's trainee.","TWN":"芬里爾戰隊長，這位是艾莉絲·布雷德伍德，夜叉的實習隊員。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이번 작전에 참관을 부탁드릴 신참이에요.","JPN":"今回の作戦に立ち会わせていただく新入りです。","ENG":"Also the rookie that I wanted you to take with you on your operation.","TWN":"想要觀摩這次作戰的新人。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"젠장! 너……! 이게 무슨 짓이야……!?","JPN":"くっそ！　おまえ……！　なんの真似だ………！？","ENG":"Gah! Hey...! What was that for...?!","TWN":"可惡！你……！你搞什麼……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"방금은 내가 살려준 거야. 나중에 고마워하게 될 걸?","JPN":"今のは私が助けてあげたんだからね。後で絶対、感謝することになるよ。","ENG":"I just saved you. You'll thank me later.","TWN":"我剛剛救了你一命。以後你會感謝我的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"알고 있겠지, 야크샤 부전대장?","JPN":"ヤクシャー副戦隊長、わかっていると思うが……","ENG":"I don’t need to elaborate, do I, Yaksha Deputy Commander?","TWN":"夜叉副戰隊長，你知道的吧？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"우리 전대의 작전 사항은 관리국 내에서도 기밀이라 외부에 노출되면 안 돼.","JPN":"うちの戦隊の作戦事項は、管理局内でも機密扱いとなっている。","ENG":"My division's operations are kept confidential even within the Administration.","TWN":"我們戰隊的作戰細節即使在管理局內部也是保密的，絕對不能向外界透露。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"하지만 야크샤와 라이오넬에게는 신세를 진 적이 있지.","JPN":"だが、ヤクシャーとライオネルには世話になったことがあるからな。","ENG":"But I do owe Lionel and Yaksha a favor.","TWN":"但我曾經欠過夜叉和萊諾的人情。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그러니 작전 사항을 외부에 노출하지 않는 조건이라면, 신참의 작전 참관을 허락하겠다.","JPN":"作戦事項を外部に漏らさないと約束してくれるなら、新入りの立ち会いを許可する。","ENG":"So, I will allow her to come along, provided she does not disclose the details of our operation.","TWN":"所以，在作戰細節不對外透露的情況下，我會允許新兵觀摩作戰。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"감사합니다. 펜릴 전대장님.","JPN":"ありがとうございます、フェンリル戦隊長。","ENG":"Thank you, Fenrir Commander.","TWN":"謝謝你，芬里爾戰隊長。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"어? 그럼 이번에는 소방관 아줌마랑 같이 싸우는 거야?","JPN":"え？　じゃあ今回は消防士おばさんと一緒に戦うの？","ENG":"Huh? Am I fighting alongside the firefighter lady?","TWN":"呃？那麼，這次要和消防員阿姨一起戰鬥嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"재밌겠다! 잘 해보자고, 아줌마!","JPN":"楽しそう！　がんばろうね、おばさん！","ENG":"That sounds like fun! Let's do this!","TWN":"很有趣欸！一起好好表現吧，阿姨！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"수연아, 다른 전대 분께 그게 무슨 말버릇이야.","JPN":"キズナ、他所の戦隊の方にそんな言い方はだめだろう。","ENG":"Sooyeon, where are your manners?","TWN":"秀妍，你怎麼和其他戰隊成員說話呢？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"원래 수연이가 사람 보는 눈이 없어서요.","JPN":"キズナは人を見る目がないんです。","ENG":"I'm sorry. She has bad people skills.","TWN":"秀妍這個人說話本來就很直接。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"너무 마음에 담아두지 않으셨으면, 좋겠습니다. 앨리스 전대원님.","JPN":"キズナの言葉はあまり気に留めないでください、アリスさん。","ENG":"I hope you don't take it too personally, Ms. Braidwood.","TWN":"希望你不要太放在心上，艾莉絲戰隊員。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……꼬맹이 전대장에 왈가닥 여고생, 거기에 멀쑥한 샌님까지.","JPN":"ちびっこ戦隊長に、お転婆女子高生。ヒョロっとした堅物まで。","ENG":"...A kid Commander, a tomboy, and a lanky dweeb.","TWN":"……小鬼戰隊長，瘋丫頭女高中生，再加上那邊的瘦高個。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"어이, 토끼녀. 정말 저런 녀석들을 믿어도 되는 거야?","JPN":"おい、ウサギ女。本当にあんなやつらを信用していいのか？","ENG":"Hey, bunny ears. Can we really trust them?","TWN":"喂，兔耳朵。我們真的可以相信這些人嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"뭐, 곧 알게 될 거야.","JPN":"そのうちわかるよ。","ENG":"Well, you'll find out soon enough.","TWN":"唔，你很快就會知道了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"특히, 저 아이는 관리국 최연소 전대장이 될 뻔한 천재 중에 천재야.","JPN":"特にあの子。あの子は管理局で最年少戦隊長になるかもしれなかった、天才の中の天才よ。","ENG":"Especially her. That girl is a genius among geniuses who almost became the youngest Commander in the Administration.","TWN":"尤其是那個孩子，更是天才中的天才，差一點就成為了管理局最年輕的戰隊長。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"단순히 CRF 방출에 의한 위력으로 따지면, 관리국에서도 손꼽을 정도로 뛰어나거든.","JPN":"CRF放出による威力だけで考えても、管理局でも屈指の逸材だからね。","ENG":"Just looking at her CRF output, she's one of the best in the Administration.","TWN":"單從CRF釋放的威力來看，即便是在管理局也是數一數二的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네 좋은 본보기가 되겠지.","JPN":"いい勉強になるはずよ。","ENG":"I think she'll be a good role model for you.","TWN":"她會成為你的好榜樣的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……전혀 신뢰가 안 되는데 말이야.","JPN":"……まったく信用できないんだけど。","ENG":"...I don't think so.","TWN":"……我才不相信呢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"기대해도 좋아, 길고양이.","JPN":"楽しみにしていて、野良猫。","ENG":"You're in for a surprise, stray cat.","TWN":"好好看著吧，流浪貓。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 뭘 상상하든, 저 아이의 싸움은 상상 그 이상을 보여줄 테니까.","JPN":"あなたが何を想像しようと、あの子との戦いはそれを越えるものを見せてくれるでしょうから。","ENG":"Whatever you're imagining, her fighting is going to show beyond that.","TWN":"那孩子的戰鬥力超乎你的想像。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"subtitle","speaker":null,"text":{"KOREA":"작전 구역 <color=#ffd34c>버뮤다 포인트</color>","JPN":"作戦区域<color=#ffd34c>バミューダポイント</color>","ENG":"Operation Area <color=#ffd34c>Bermuda Point</color>","TWN":"作戰區域<color=#ffd34c>百慕達三角洲</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"전대장님, 거의 도착했습니다.","JPN":"戦隊長、そろそろ着きます。","ENG":"Commander, we're almost at the destination.","TWN":"戰隊長，我們快到了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……그동안의 침식 현상이랑은 차원이 달라.","JPN":"……今までの侵食現象とは桁が違う。","ENG":"...This Counterside Effect feels different from the previous ones.","TWN":"……這次侵蝕現象，和之前完全是不同等級。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"온 몸이 찌릿찌릿 저릴 정도야. 여긴 대체……?","JPN":"全身がビリビリするくらいだ。ここはいったい……？","ENG":"My whole body is tingling. Where are we...?","TWN":"渾身有種刺撓的感覺。這到底是什麼地方啊……？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"버뮤다 포인트라고 해요. 관리국의 집중 관리 구역 중 하나죠.","JPN":"バミューダポイントと言います。管理局の集中管理区域の一つです。","ENG":"It's called Bermuda Point. It's one of the Administration's intensively managed zones.","TWN":"這裡是百慕達三角洲，是管理局的集中管理區之一。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"버뮤다 포인트……?","JPN":"バミューダポイント……？","ENG":"Bermuda Point...?","TWN":"百慕達三角洲……？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"설마, 그 배나 비행기가 자주 사라진다는 거길 말하는 거야?","JPN":"まさかあの、船や飛行機がよく行方不明になる場所か？","ENG":"Are you talking about that place where airplanes and ships go missing?","TWN":"那個經常有船隻和飛機失蹤的地方？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"네, 아직까지 현실세계에서 CSE 레벨이 4단계까지 올라가는 경우는 극히 드물지만.","JPN":"はい。今のところ、現実世界でCSEレベルが4段階まで上がるケースは極稀ですが。","ENG":"Yes. It's unusual for a CSE Level 4 to show up in the Normalside.","TWN":"沒錯，現世中很少有CSE等級能升至4的區域。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"버뮤다 포인트에서는 가끔 국지적으로 CSE 레벨이 4단계까지 올라가곤 해요.","JPN":"バミューダポイントでは、時々局地的にCSEレベルが4段階まで上がることがあります。","ENG":"But Bermuda Point has times when it does go up to CSE Level 4.","TWN":"而百慕達三角洲當地的CSE等級偶爾會達到這個程度。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"때때로 인도양에서만 발견되던 4종 침식체가 출몰할 때도 있고요.","JPN":"たまにインド洋でしか発見されなかった第4種侵食体が出現することだってありますしね。","ENG":"Sometimes, a Category 4 C.O. that would only be found in the Indian Ocean would appear.","TWN":"有時，還會出現僅在印度洋發現過的4類侵蝕體。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"흥! 스승님이 가르쳐 주신대로만 하면, 그깟 4종 침식체 따위 아무것도 아니라고!","JPN":"ふん！　師匠の教え通りにすれば、第4種侵食体だってへっちゃらだから！","ENG":"Hmph! If I do as Master taught me, a Category 4 C.O. is a cinch!","TWN":"哼！只要按照師父教的去做，那種4類侵蝕體根本不算什麼！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"그렇죠, 스승님?","JPN":"ね、師匠？","ENG":"Right, Master?","TWN":"對吧，師父？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"방심하지 마라, 이수연.","JPN":"油断は禁物だ、カナミ。","ENG":"Don't let your guard down, Sooyeon.","TWN":"別掉以輕心，秀妍。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"원래 인간의 힘으로는 4종 이상의 침식체와 싸워서 이길 수 없어.","JPN":"本来人間の力では第4種以上の侵食体には敵わない。","ENG":"No human can fight and win against a Category 4 with only their strength alone.","TWN":"以人類的力量，根本無法對抗4類侵蝕體。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"방심했다가 공격을 허용하게 되면, 아무리 너라도 치명상을 입게 될 거다.","JPN":"油断して攻撃を受けたら、いくらお前でも致命傷を負いかねない。","ENG":"If you get distracted and get hit, even you'll suffer fatal injuries.","TWN":"如果因為分心被擊中，就算是你也可能會受重傷。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"하핫, 그 얘기는 이미 몇 번이나 들었다고요!","JPN":"あははっ、それは何回も聞きました！","ENG":"Haha! I've heard that too many times to count!","TWN":"哈哈，這些話我聽過很多次了！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"하지만 스승님은 이렇게도 말씀하셨죠.","JPN":"でも師匠はこんなことも言ってましたよね。","ENG":"But you also said this to me, Master.","TWN":"但師父這樣說過吧。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>현실의 싸움이라는 건, 단순한 전투력 수치로 결정되는 게 아니다. </color>","JPN":"<color=#ffd34c>現実の戦いというものは、単に戦闘力の数値で決まるものではない。</color>","ENG":"<color=#ffd34c>But reality isn't all about numbers and categories.</color>","TWN":"<color=#ffd34c>戰鬥的勝負並非僅僅取決於戰鬥力數值的高低。</color>"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>강하다고 해서 반드시 이기는 것도 아니고, 약하다고 해서 반드시 지는 것도 아니다.</color>","JPN":"<color=#ffd34c>強いからと言って勝つわけでも、弱いからと言って負けるわけでもない。</color>","ENG":"<color=#ffd34c>Being strong doesn't necessarily mean you win, and being weak doesn't necessarily mean you lose.</color>","TWN":"<color=#ffd34c>強不代表著會贏，弱也不代表著會輸。</color>"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"헤헤, 걱정마세요, 스승님!","JPN":"へへ、大丈夫ですよ。師匠！","ENG":"Hehe, don't worry, Master!","TWN":"嘿嘿，師父，你就放心吧！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"전 스승님의 가르침대로, 항상 한계의 한계를 넘어왔으니까요!","JPN":"私は師匠の教え通り、いつも限界の限界を越えてきましたから！","ENG":"Because I've always been going beyond my limits, just like you taught me!","TWN":"我一直按照師父所教的那樣，不斷挑戰著自己的極限！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"전대장님, 작전 구역의 CSE 레벨이 3단계에서 점진적으로 4단계로 올라가고 있습니다.","JPN":"戦隊長、作戦区域のCSEレベルが3段階から徐々に4段階へと上がりつつあります。","ENG":"Commander, the operation area's CSE Level is gradually increasing from 3 to 4.","TWN":"戰隊長，作戰區域的CSE等級正在逐步從3升至4。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"이 이상은 헬기로 접근하는 게 어렵겠습니다.","JPN":"これ以上ヘリで近づくことは難しいかと。","ENG":"It'll be difficult to get any closer with the helicopter.","TWN":"直升機很難接近該地區了。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"……좋았어!","JPN":"……よし！","ENG":"...Okay!","TWN":"……很好！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"이 작전에서 스승님의 가르침에 부응하기 위해, 새로 구상한 필살기를 보여주는 거야!","JPN":"師匠の教えに応えられるように、この作戦で新しい必殺技を披露するんだ！","ENG":"To live up to Master's teachings, I'll show her my new special move!","TWN":"為了不辜負師父的教誨，這次作戰我會向師父展示全新設計的必殺技！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"필살기……?","JPN":"必殺技……？","ENG":"Special move...?","TWN":"必殺技……？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESUYEON_ADMIN_NULL_NULL","text":{"KOREA":"간다! 이수연, 출격합니다!","JPN":"行くぞー！　カナミ・キズナ、出撃します！","ENG":"Let's do this! Lee Sooyeon, diving in!","TWN":"去吧！李秀妍，出擊！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESUYEON_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"야, 수연아! 또 혼자 뛰어들면 어떡해!","JPN":"ちょっと、キズナ！　また一人で飛び込んじゃダメだろう！","ENG":"Hey, Sooyeon! You can't just jump out by yourself!","TWN":"啊，秀妍！不要一個人先跳下去！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"자, 잠깐……!? 저 녀석 지금, 이 높이에서 낙하산도 없이 뛰어내린 거야……!?","JPN":"う、嘘だろ……！？　あいつ、この高度からパラシュートも装備せずに飛び降りた……！？","ENG":"W-wait...! Did she just jump out of the helicopter without a parachute at this height...?!","TWN":"等、等等……？！這麼高的地方，那個傢伙居然沒帶降落傘嗎……？！"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"호들갑 떨지 마라, 신참.","JPN":"騒ぐな、新入り。","ENG":"It's not a big deal, rookie.","TWN":"別太驚訝了，新人。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"우리 전대는 강습전이 특기다. 낙하산 같은 건, 처음부터 준비하지 않았어.","JPN":"うちの戦隊は強襲を特技としている。パラシュートなど初めから用意していない。","ENG":"My division specializes in assault operations. We didn't prepare any parachutes in the first place.","TWN":"強襲是我們戰隊的強項。從一開始就沒有準備降落傘之類的東西。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐, 뭐라고요……?","JPN":"な、なんですと……？","ENG":"W-what...?","TWN":"什、什麼……？"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그보다 여기서 저 녀석이 싸우는걸, 한순간도 놓치지 말고 잘 관찰하도록.","JPN":"それより、あいつが戦う様子をここでよく観察し、目に焼き付けるといい。","ENG":"Anyway, don't take your eyes off of her and observe how she fights.","TWN":"你在這裡好好觀察她的戰鬥，不要放過任何一個瞬間。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"그게 오늘 네가 할 임무다. 신참.","JPN":"それが今日お前がやるべき任務だ。","ENG":"That's your mission for today, rookie.","TWN":"這就是你今天的任務，新人。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_NULL","text":{"KOREA":"뭐, 그것도 저 녀석이 적당히 해줄 때의 얘기겠지만.","JPN":"まあ、あいつがほどほどにやってくれる場合の話だが。","ENG":"Well, that is if she goes easy on them.","TWN":"唔，我說的是那傢伙正常時候的樣子。"},"stage":{"bg":"HELI_NIGHT_2","bgm":"THEMA_COFFIN_FULL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};